### 5. **apps/web Component & Hook Patterns**

**Path**: `/apps/web/src/`

**Framework**: React 19.0.0 + TanStack Router + TanStack Query

**Key Dependencies**:
```json
{
  "@base-ui/react": "^1.2.0",
  "@lexical/react": "^0.41.0",
  "@tanstack/react-query": "^5.90.0",
  "@tanstack/react-router": "^1.160.2",
  "effect": "catalog:",
  "zustand": "^5.0.11",
  "lucide-react": "^0.564.0",
  "tailwindcss": "^4.0.0"
}
```

#### **UI Component Pattern** (Base-UI + CVA + Tailwind):

```typescript
// apps/web/src/components/ui/card.tsx
"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import { cn } from "~/lib/utils";

function Card({ className, render, ...props }: useRender.ComponentProps<"div">) {
  const defaultProps = {
    className: cn(
      "relative flex flex-col rounded-2xl border bg-card",
      className,
    ),
    "data-slot": "card",
  };

  return useRender({
    defaultTagName: "div",
    props: mergeProps<"div">(defaultProps, props),
    render,
  });
}
```

**Pattern Key Points**:
- Uses `@base-ui/react` for unstyled component primitives
- `mergeProps` for intelligent prop composition
- `useRender` for composition pattern (render prop optional)
- `data-slot` attributes for CSS selectors
- Tailwind CSS with custom configuration
- CVA (class-variance-authority) for component variants

#### **Grouped Component Example** (Multi-part components):

```typescript
// apps/web/src/components/ui/field.tsx
function Field({ className, ...props }: FieldPrimitive.Root.Props) {
  return (
    <FieldPrimitive.Root
      className={cn("flex flex-col items-start gap-2", className)}
      data-slot="field"
      {...props}
    />
  );
}

function FieldLabel({ className, ...props }: FieldPrimitive.Label.Props) {
  return (
    <FieldPrimitive.Label
      className={cn("inline-flex items-center gap-2 font-medium", className)}
      data-slot="field-label"
      {...props}
    />
  );
}
// ... FieldItem, FieldDescription, FieldError, FieldControl

export { Field, FieldLabel, FieldDescription, FieldError, FieldControl, FieldItem };
```

#### **Domain Component Pattern** (Feature components with logic):

```typescript
// apps/web/src/components/PlanSidebar.tsx
interface PlanSidebarProps {
  activePlan: ActivePlanState | null;
  activeProposedPlan: LatestProposedPlanState | null;
  markdownCwd: string | undefined;
  workspaceRoot: string | undefined;
  onClose: () => void;
}

const PlanSidebar = memo(function PlanSidebar({
  activePlan,
  activeProposedPlan,
  markdownCwd,
  workspaceRoot,
  onClose,
}: PlanSidebarProps) {
  const [proposedPlanExpanded, setProposedPlanExpanded] = useState(false);
  const [isSavingToWorkspace, setIsSavingToWorkspace] = useState(false);

  const handleCopyPlan = useCallback(() => {
    if (!planMarkdown) return;
    void navigator.clipboard.writeText(planMarkdown);
  }, [planMarkdown]);

  // Component implementation
});
```

**Pattern Key Points**:
- Named, memoized functional components
- Proper prop interfaces
- `useCallback` for event handlers
- `useState` for local UI state
- Integration with external APIs via hooks

#### **Hook Patterns**:

**useSyncExternalStore Hook** (Theme management):
```typescript
// apps/web/src/hooks/useTheme.ts
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;

  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  return { theme, setTheme, resolvedTheme } as const;
}
```

