**Example - Model Utilities**:
```typescript
// packages/shared/src/model.ts
export function getModelOptions(provider: ProviderKind = "codex") {
  return MODEL_OPTIONS_BY_PROVIDER[provider];
}

export function normalizeModelSlug(
  model: string | null | undefined,
  provider: ProviderKind = "codex",
): ModelSlug | null {
  const trimmed = model?.trim();
  if (!trimmed) return null;

  const aliases = MODEL_SLUG_ALIASES_BY_PROVIDER[provider];
  const aliased = aliases[trimmed];
  return typeof aliased === "string" ? aliased : (trimmed as ModelSlug);
}
```

**Example - Git Utilities**:
```typescript
// packages/shared/src/git.ts
export function sanitizeBranchFragment(raw: string): string {
  const normalized = raw.trim().toLowerCase().replace(/['"`]/g, "");
  return normalized.replace(/[^a-z0-9/_-]+/g, "-").slice(0, 64);
}

export function resolveAutoFeatureBranchName(
  existingBranchNames: readonly string[],
  preferredBranch?: string,
): string {
  const resolvedBase = sanitizeFeatureBranchName(preferredBranch || "feature/update");
  const existingNames = new Set(existingBranchNames.map(b => b.toLowerCase()));

  if (!existingNames.has(resolvedBase)) return resolvedBase;

  let suffix = 2;
  while (existingNames.has(`${resolvedBase}-${suffix}`)) suffix++;
  return `${resolvedBase}-${suffix}`;
}
```

