48	function readPersistedState(): AppState {
49	  if (typeof window === "undefined") return initialState;
50	  try {
51	    const raw = window.localStorage.getItem(PERSISTED_STATE_KEY);
52	    if (!raw) return initialState;
53	    const parsed = JSON.parse(raw) as { expandedProjectCwds?: string[] };
54	    persistedExpandedProjectCwds.clear();
55	    for (const cwd of parsed.expandedProjectCwds ?? []) {
56	      if (typeof cwd === "string" && cwd.length > 0) {
57	        persistedExpandedProjectCwds.add(cwd);
58	      }
59	    }
60	    return { ...initialState };
61	  } catch {
62	    return initialState;
63	  }
64	}
