/** Color slots that every theme must define. */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

/** A complete theme definition. */
export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#e5e5e5",
      accent: "#6366f1",
      sidebar: "#111113",
      editor: "#0a0a0b",
      terminal: "#09090b",
      statusBar: "#111113",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1c1c1e",
      accent: "#4f46e5",
      sidebar: "#f5f5f7",
      editor: "#ffffff",
      terminal: "#f5f5f7",
      statusBar: "#f0f0f2",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#020217",
      foreground: "#c8c8d0",
      accent: "#818cf8",
      sidebar: "#0a0a24",
      editor: "#020217",
      terminal: "#01010f",
      statusBar: "#0a0a24",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
] as const;

const themeMap = new Map<string, Theme>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

/** Return the theme with the given id, or `undefined` if not found. */
export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

/** Return the full list of built-in themes. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

