import { useCallback, useEffect, useSyncExternalStore } from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

type ColorScheme = "light" | "dark" | "system";
type ThemeSnapshot = {
  colorScheme: ColorScheme;
  themeId: string;
  systemDark: boolean;
};

const COLOR_SCHEME_STORAGE_KEY = "t3code:theme";
const THEME_ID_STORAGE_KEY = "t3code:custom-theme:v1";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";
const DEFAULT_THEME_ID = "t3-dark";

/** CSS custom properties written by the theme system. */
const THEME_CSS_PROPERTIES = [
  "--theme-background",
  "--theme-foreground",
  "--theme-accent",
  "--theme-sidebar",
  "--theme-editor",
  "--theme-terminal",
  "--theme-status-bar",
  "--theme-font-family",
  "--theme-font-size",
] as const;

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredColorScheme(): ColorScheme {
  const raw = localStorage.getItem(COLOR_SCHEME_STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredThemeId(): string {
  return localStorage.getItem(THEME_ID_STORAGE_KEY) ?? DEFAULT_THEME_ID;
}

function applyColorScheme(colorScheme: ColorScheme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark =
    colorScheme === "dark" || (colorScheme === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function applyThemeColors(theme: Theme) {
  const root = document.documentElement;
  root.style.setProperty("--theme-background", theme.colors.background);
  root.style.setProperty("--theme-foreground", theme.colors.foreground);
  root.style.setProperty("--theme-accent", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${String(theme.fontSize)}px`);
}

function clearThemeColors() {
  const root = document.documentElement;
  for (const prop of THEME_CSS_PROPERTIES) {
    root.style.removeProperty(prop);
  }
}

function applyStoredTheme() {
  const themeId = getStoredThemeId();
  const theme = getTheme(themeId);
  if (theme) {
    applyThemeColors(theme);
  } else {
    clearThemeColors();
  }
}

// Apply immediately on module load to prevent flash
applyColorScheme(getStoredColorScheme());
applyStoredTheme();

function getSnapshot(): ThemeSnapshot {
  const colorScheme = getStoredColorScheme();
  const themeId = getStoredThemeId();
  const systemDark = colorScheme === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.colorScheme === colorScheme &&
    lastSnapshot.themeId === themeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { colorScheme, themeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredColorScheme() === "system") applyColorScheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === COLOR_SCHEME_STORAGE_KEY) {
      applyColorScheme(getStoredColorScheme(), true);
      emitChange();
    }
    if (e.key === THEME_ID_STORAGE_KEY) {
      applyStoredTheme();
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const colorScheme = snapshot.colorScheme;
  const themeId = snapshot.themeId;

  const resolvedTheme: "light" | "dark" =
    colorScheme === "system"
      ? snapshot.systemDark
        ? "dark"
        : "light"
      : colorScheme;

  const activeTheme = getTheme(themeId) ?? getTheme(DEFAULT_THEME_ID)!;
  const availableThemes = listThemes();

  const setTheme = useCallback((next: ColorScheme) => {
    localStorage.setItem(COLOR_SCHEME_STORAGE_KEY, next);
    applyColorScheme(next, true);
    emitChange();
  }, []);

  const setCustomTheme = useCallback((nextId: string) => {
    localStorage.setItem(THEME_ID_STORAGE_KEY, nextId);
    const theme = getTheme(nextId);
    if (theme) {
      applyThemeColors(theme);
    }
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyColorScheme(colorScheme);
  }, [colorScheme]);

  useEffect(() => {
    const theme = getTheme(themeId);
    if (theme) {
      applyThemeColors(theme);
    }
  }, [themeId]);

  return {
    /** Current color scheme preference (light / dark / system). */
    theme: colorScheme,
    /** The actual resolved mode after evaluating system preference. */
    resolvedTheme,
    /** The full active custom theme object. */
    activeTheme,
    /** All available custom themes. */
    availableThemes,
    /** Set the color scheme preference. */
    setTheme,
    /** Set the active custom theme by id. */
    setCustomTheme,
  } as const;
}

