import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "~/hooks/useTheme";

function ThemeSwatch({ theme, compact }: { theme: Theme; compact?: boolean }) {
  const size = compact ? "size-3" : "size-4";
  return (
    <div className="flex items-center gap-1" aria-hidden="true">
      <span
        className={`${size} shrink-0 rounded-full border border-border`}
        style={{ backgroundColor: theme.colors.background }}
      />
      <span
        className={`${size} shrink-0 rounded-full border border-border`}
        style={{ backgroundColor: theme.colors.accent }}
      />
      <span
        className={`${size} shrink-0 rounded-full border border-border`}
        style={{ backgroundColor: theme.colors.foreground }}
      />
    </div>
  );
}

export function ThemeSelector() {
  const { activeTheme, availableThemes, setCustomTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Custom theme">
      {availableThemes.map((theme) => {
        const selected = activeTheme.id === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setCustomTheme(theme.id)}
          >
            <span className="flex items-center gap-3">
              <ThemeSwatch theme={theme} />
              <span className="text-sm font-medium">{theme.name}</span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

