1	import { useCallback, useEffect, useSyncExternalStore } from "react";
2	import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";
3	
4	type ColorScheme = "light" | "dark" | "system";
5	type ThemeSnapshot = {
6	  colorScheme: ColorScheme;
7	  themeId: string;
8	  systemDark: boolean;
9	};
10	
11	const COLOR_SCHEME_STORAGE_KEY = "t3code:theme";
12	const THEME_ID_STORAGE_KEY = "t3code:custom-theme:v1";
13	const MEDIA_QUERY = "(prefers-color-scheme: dark)";
14	const DEFAULT_THEME_ID = "t3-dark";
15	
16	/** CSS custom properties written by the theme system. */
17	const THEME_CSS_PROPERTIES = [
18	  "--theme-background",
19	  "--theme-foreground",
20	  "--theme-accent",
21	  "--theme-sidebar",
22	  "--theme-editor",
23	  "--theme-terminal",
24	  "--theme-status-bar",
25	  "--theme-font-family",
26	  "--theme-font-size",
27	] as const;
28	
29	let listeners: Array<() => void> = [];
30	let lastSnapshot: ThemeSnapshot | null = null;
31	
32	function emitChange() {
33	  for (const listener of listeners) listener();
34	}
35	
36	function getSystemDark(): boolean {
37	  return window.matchMedia(MEDIA_QUERY).matches;
38	}
39	
40	function getStoredColorScheme(): ColorScheme {
41	  const raw = localStorage.getItem(COLOR_SCHEME_STORAGE_KEY);
42	  if (raw === "light" || raw === "dark" || raw === "system") return raw;
43	  return "system";
44	}
45	
46	function getStoredThemeId(): string {
47	  return localStorage.getItem(THEME_ID_STORAGE_KEY) ?? DEFAULT_THEME_ID;
48	}
49	
50	function applyColorScheme(colorScheme: ColorScheme, suppressTransitions = false) {
51	  if (suppressTransitions) {
52	    document.documentElement.classList.add("no-transitions");
53	  }
54	  const isDark =
55	    colorScheme === "dark" || (colorScheme === "system" && getSystemDark());
56	  document.documentElement.classList.toggle("dark", isDark);
57	  if (suppressTransitions) {
58	    // Force a reflow so the no-transitions class takes effect before removal
59	    // oxlint-disable-next-line no-unused-expressions
60	    document.documentElement.offsetHeight;
61	    requestAnimationFrame(() => {
62	      document.documentElement.classList.remove("no-transitions");
63	    });
64	  }
65	}
66	
67	function applyThemeColors(theme: Theme) {
68	  const root = document.documentElement;
69	  root.style.setProperty("--theme-background", theme.colors.background);
70	  root.style.setProperty("--theme-foreground", theme.colors.foreground);
71	  root.style.setProperty("--theme-accent", theme.colors.accent);
72	  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
73	  root.style.setProperty("--theme-editor", theme.colors.editor);
74	  root.style.setProperty("--theme-terminal", theme.colors.terminal);
75	  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
76	  root.style.setProperty("--theme-font-family", theme.fontFamily);
77	  root.style.setProperty("--theme-font-size", `${String(theme.fontSize)}px`);
78	}
79	
80	function clearThemeColors() {
81	  const root = document.documentElement;
82	  for (const prop of THEME_CSS_PROPERTIES) {
83	    root.style.removeProperty(prop);
84	  }
85	}
86	
87	function applyStoredTheme() {
88	  const themeId = getStoredThemeId();
89	  const theme = getTheme(themeId);
90	  if (theme) {
91	    applyThemeColors(theme);
92	  } else {
93	    clearThemeColors();
94	  }
95	}
96	
97	// Apply immediately on module load to prevent flash
98	applyColorScheme(getStoredColorScheme());
99	applyStoredTheme();
100	
101	function getSnapshot(): ThemeSnapshot {
102	  const colorScheme = getStoredColorScheme();
103	  const themeId = getStoredThemeId();
104	  const systemDark = colorScheme === "system" ? getSystemDark() : false;
105	
106	  if (
107	    lastSnapshot &&
108	    lastSnapshot.colorScheme === colorScheme &&
109	    lastSnapshot.themeId === themeId &&
110	    lastSnapshot.systemDark === systemDark
111	  ) {
112	    return lastSnapshot;
113	  }
114	
115	  lastSnapshot = { colorScheme, themeId, systemDark };
116	  return lastSnapshot;
117	}
118	
119	function subscribe(listener: () => void): () => void {
120	  listeners.push(listener);
121	
122	  // Listen for system preference changes
123	  const mq = window.matchMedia(MEDIA_QUERY);
124	  const handleChange = () => {
125	    if (getStoredColorScheme() === "system") applyColorScheme("system", true);
126	    emitChange();
127	  };
128	  mq.addEventListener("change", handleChange);
129	
130	  // Listen for storage changes from other tabs
131	  const handleStorage = (e: StorageEvent) => {
132	    if (e.key === COLOR_SCHEME_STORAGE_KEY) {
133	      applyColorScheme(getStoredColorScheme(), true);
134	      emitChange();
135	    }
136	    if (e.key === THEME_ID_STORAGE_KEY) {
137	      applyStoredTheme();
138	      emitChange();
139	    }
140	  };
141	  window.addEventListener("storage", handleStorage);
142	
143	  return () => {
144	    listeners = listeners.filter((l) => l !== listener);
145	    mq.removeEventListener("change", handleChange);
146	    window.removeEventListener("storage", handleStorage);
147	  };
148	}
149	
150	export function useTheme() {
151	  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
152	  const colorScheme = snapshot.colorScheme;
153	  const themeId = snapshot.themeId;
154	
155	  const resolvedTheme: "light" | "dark" =
156	    colorScheme === "system"
157	      ? snapshot.systemDark
158	        ? "dark"
159	        : "light"
160	      : colorScheme;
161	
162	  const activeTheme = getTheme(themeId) ?? getTheme(DEFAULT_THEME_ID)!;
163	  const availableThemes = listThemes();
164	
165	  const setTheme = useCallback((next: ColorScheme) => {
166	    localStorage.setItem(COLOR_SCHEME_STORAGE_KEY, next);
167	    applyColorScheme(next, true);
168	    emitChange();
169	  }, []);
170	
171	  const setCustomTheme = useCallback((nextId: string) => {
172	    localStorage.setItem(THEME_ID_STORAGE_KEY, nextId);
173	    const theme = getTheme(nextId);
174	    if (theme) {
175	      applyThemeColors(theme);
176	    }
177	    emitChange();
178	  }, []);
179	
180	  // Keep DOM in sync on mount/change
181	  useEffect(() => {
182	    applyColorScheme(colorScheme);
183	  }, [colorScheme]);
184	
185	  useEffect(() => {
186	    const theme = getTheme(themeId);
187	    if (theme) {
188	      applyThemeColors(theme);
189	    }
190	  }, [themeId]);
191	
192	  return {
193	    /** Current color scheme preference (light / dark / system). */
194	    theme: colorScheme,
195	    /** The actual resolved mode after evaluating system preference. */
196	    resolvedTheme,
197	    /** The full active custom theme object. */
198	    activeTheme,
199	    /** All available custom themes. */
200	    availableThemes,
201	    /** Set the color scheme preference. */
202	    setTheme,
203	    /** Set the active custom theme by id. */
204	    setCustomTheme,
205	  } as const;
206	}
